Alias.script:
--syntax: tgts
weaving = weaving or {} local tgt = targeting.currtgt
if tgt then local color = targeting.colors[tgt] or "white" cecho(f"Your current target is: <{color}>{tgt}
") end
cecho(f"Your current pk mode is: {targeting.pkmode}
") if targeting.pkmode == "channel" then cecho("Longweave set to: "..(weaving.longweave or "none").."
") cecho("Shortweave set to: "..(weaving.shortweave or "none").."
") end
for i, tgt in ipairs(targeting) do local color = targeting.colors[tgt] or "white" cecho(f"Target {i} = <{color}>{tgt}
") end

--syntax: pkmode
local pkmodes = {"bash", "charge", "backstab", "channel", "none"}
local index = table.index_of(pkmodes, targeting.pkmode) if index then index = (index % table.size(pkmodes))+1 targeting.pkmode = pkmodes[index] else targeting.pkmode = pkmodes[1] end cecho(f"PK method set to: {targeting.pkmode}\n")
